def ctz64(n: UInt64) -> Int:
    if n == 0:
        return 64
    var x = n
    var c = 0
    while (x & 1) == 0:
        c += 1
        x >>= 1
    return c

def clz64(n: UInt64) -> Int:
    if n == 0:
        return 64
    var c = 0
    var mask = UInt64(1) << 63
    while (n & mask) == 0:
        c += 1
        mask >>= 1
    return c

def reverse_bits(n: UInt64) -> UInt64:
    var r = UInt64(0)
    var x = n
    for _ in range(64):
        r = (r << 1) | (x & 1)
        x >>= 1
    return r

