def set_bit(n: UInt64, i: Int) -> UInt64:
    return n | (UInt64(1) << i)

def clear_bit(n: UInt64, i: Int) -> UInt64:
    return n & ~(UInt64(1) << i)

def toggle_bit(n: UInt64, i: Int) -> UInt64:
    return n ^ (UInt64(1) << i)

def get_bit(n: UInt64, i: Int) -> Int:
    return Int((n >> i) & 1)

def next_pow2(n: UInt64) -> UInt64:
    if n <= 1:
        return 1
    var p = UInt64(1)
    while p < n:
        p <<= 1
    return p

def binary_to_gray(n: UInt64) -> UInt64:
    return n ^ (n >> 1)

def gray_to_binary(g: UInt64) -> UInt64:
    var b = UInt64(0)
    var x = g
    while x != 0:
        b ^= x
        x >>= 1
    return b

def gcd_rec(a: Int, b: Int) -> Int:
    if b == 0:
        return a
    return gcd_rec(b, a % b)

def power_rec(base: Int, exp: Int) -> Int:
    if exp == 0:
        return 1
    return base * power_rec(base, exp - 1)

def sum_digits_rec(n: Int) -> Int:
    if n < 10:
        return n
    return n % 10 + sum_digits_rec(n // 10)

def hanoi(n: Int) -> Int:
    if n <= 0:
        return 0
    return 2 * hanoi(n - 1) + 1

def catalan(n: Int) -> Int:
    if n <= 1:
        return 1
    var r = 0
    for i in range(n):
        r += catalan(i) * catalan(n - 1 - i)
    return r

