def is_odd(n: Int) -> Bool:
    if n == 0:
        return False
    return is_even(n - 1)

def is_even(n: Int) -> Bool:
    if n == 0:
        return True
    return is_odd(n - 1)

def classify_number(n: Int) -> Int:
    if n < 0:
        return -1
    elif n == 0:
        return 0
    else:
        return 1

def fizzbuzz_count(n: Int) -> Int:
    var c = 0
    for i in range(1, n + 1):
        if i % 15 == 0:
            c += 3
        elif i % 3 == 0:
            c += 1
        elif i % 5 == 0:
            c += 2
    return c

def leap_year(y: Int) -> Int:
    if y % 400 == 0:
        return 1
    if y % 100 == 0:
        return 0
    if y % 4 == 0:
        return 1
    return 0

def days_in_month(m: Int, leap: Int) -> Int:
    if m == 2:
        return 29 if leap != 0 else 28
    if m == 4 or m == 6 or m == 9 or m == 11:
        return 30
    return 31

def clamp_int(x: Int, lo: Int, hi: Int) -> Int:
    if x < lo:
        return lo
    if x > hi:
        return hi
    return x

def dispatch_op(op: Int, a: Int, b: Int) -> Int:
    if op == 0:
        return a + b
    elif op == 1:
        return a - b
    elif op == 2:
        return a * b
    elif op == 3:
        return a // b if b != 0 else 0
    else:
        return -1

def collatz(n: Int, cap: Int) -> Int:
    var x = n
    var steps = 0
    while x != 1 and steps < cap:
        if x % 2 == 0:
            x //= 2
        else:
            x = 3 * x + 1
        steps += 1
    return steps

def nested_loop_count(n: Int) -> Int:
    var c = 0
    for i in range(n):
        for j in range(i, n):
            if (i + j) % 2 == 0:
                c += 1
    return c
